package jetbrains.mps.kotlin.make;

/*Generated by MPS */

import org.jetbrains.kotlin.cli.common.messages.MessageCollector;
import jetbrains.mps.messages.IMessageHandler;
import java.util.Set;
import java.io.File;
import jetbrains.mps.internal.collections.runtime.SetSequence;
import java.util.HashSet;
import org.jetbrains.annotations.NotNull;
import org.jetbrains.kotlin.cli.common.messages.CompilerMessageSeverity;
import org.jetbrains.annotations.Nullable;
import org.jetbrains.kotlin.cli.common.messages.CompilerMessageSourceLocation;
import jetbrains.mps.messages.Message;
import jetbrains.mps.make.facet.IFacet;
import org.jetbrains.kotlin.cli.common.messages.OutputMessageUtil;
import jetbrains.mps.messages.MessageKind;
import jetbrains.mps.make.MPSCompilationResult;
import java.util.Collections;
import org.jetbrains.mps.openapi.module.SModuleReference;
import java.util.Collection;

/**
 * Implementation of kotlin compiler message collector, binding to MPS messages
 */
public class MpsMessageCollector implements MessageCollector {
  private final IMessageHandler myMessageHandler;
  private final Set<File> myOutputPaths;
  private int errorCount = 0;
  private int warningCount = 0;
  private boolean hasOutput = false;

  public MpsMessageCollector(IMessageHandler messageHandler) {
    myMessageHandler = messageHandler;
    myOutputPaths = SetSequence.fromSet(new HashSet<File>());
  }

  public void clear() {
    // Nothing to do, right?
  }

  @Override
  public void report(@NotNull CompilerMessageSeverity severity, @NotNull String text, @Nullable CompilerMessageSourceLocation sourceLocation) {
    // Getting output files locations
    if (addOutput(text)) {
      hasOutput = true;
      return;
    }

    // Update counts
    errorCount += (severity.isError() ? 1 : 0);
    warningCount += (severity.isWarning() ? 1 : 0);

    if (sourceLocation != null) {
      String path = sourceLocation.getPath();
      text = path.substring(path.lastIndexOf("/") + 1) + ":" + sourceLocation.getLine() + ":" + sourceLocation.getColumn() + ": " + text;
    }
    Message message = new Message(getKind(severity), new IFacet.Name("jetbrains.mps.kotlin.make.KotlinJvmCompile").getName(), text);
    myMessageHandler.handle(message.setHintObject(sourceLocation));
  }

  private boolean addOutput(String text) {
    // At least the parsing is handled by kotlin so we can expect it to be stable :)
    OutputMessageUtil.Output fileOutput = OutputMessageUtil.parseOutputMessage(text);
    if (fileOutput == null) {
      return false;
    }

    SetSequence.fromSet(myOutputPaths).addElement(fileOutput.outputFile);
    return true;
  }

  public boolean hasErrors() {
    return errorCount > 0;
  }

  private MessageKind getKind(CompilerMessageSeverity severity) {
    switch (severity) {
      case ERROR:
      case EXCEPTION:
        return MessageKind.ERROR;

      case STRONG_WARNING:
      case WARNING:
        return MessageKind.WARNING;
      default:
        return MessageKind.INFORMATION;
    }
  }

  public MPSCompilationResult getResult() {
    // This mostly happens when compilation doesn't happen
    if (!(hasOutput) && errorCount == 0 && warningCount == 0) {
      return MPSCompilationResult.ZERO_COMPILATION_RESULT;
    }

    // TODO detect changed modules (compare output file paths and modules output paths)
    return new MPSCompilationResult(errorCount, warningCount, false, Collections.<SModuleReference>emptyList());
  }

  public Collection<File> getOutputPaths() {
    return this.myOutputPaths;
  }
}
